+    const isMarkdownImage = text[index] === '!' && text[index + 1] === '[';
+    const isMarkdownLink = text[index] === '[';
+    if (isMarkdownImage || isMarkdownLink) {
+      const style = isMarkdownImage ? options.imageStyle : options.linkStyle;
+      const markdownLink = style === 'wiki' ? parseMarkdownLink(text, index, isMarkdownImage) : null;
+      if (markdownLink && !markdownLink.target.includes('://')) {
+        const label = markdownLink.label;
+        const target = markdownLink.target;
+        if (isMarkdownImage) {
+          output += `![[${target}${label === '' || label === target ? '' : `|${label}`}]]`;
+        } else {
+          const defaultDisplay = defaultHeadingDisplay(target);
+          output += `[[${target}${label === target || label === defaultDisplay ? '' : `|${label}`}]]`;
+        }
+        index = markdownLink.end;
+        continue;
+      }
+    }
