+function isValidWikiPart(value: string): boolean {
+  return value !== '' && !/[\
\\[\\]]/.test(value);
+}
+
+function wikiImageLabel(target: string, display: string | undefined): string {
+  return display === undefined || /^\\d+(?:x\\d+)?$/.test(display) ? target : display;
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const hash = target.indexOf('#');
+  if (hash === -1) {
+    return target;
+  }
+  const page = target.substring(0, hash);
+  const heading = target.substring(hash + 1);
+  return page === '' ? heading : `${page} > ${heading}`;
